  VALUES (
    '75b32155-1255-4d17-b437-152e300521a0',
    '2026-01-19 15:00:00+00',
    'fireflies',
    '01KEVVT7APBJRPKJQT7F0EB8HJ',
    'New North <> ThreatMark: Weekly Marketing Meeting',
    '{"Kate ThreatMark","Nina Belina"}'::text[],
