-- Meeting: Encamp // Website Feedback: Nina Belina and Kyley Crews (Jenny B.) (2026-01-15 16:49:01+00)
WITH new_meeting AS (
  INSERT INTO compass_meetings (contract_id, meeting_date, source, external_id, title, participants, duration_seconds, recording_url, transcript, sentiment, raw_metadata, created_at, updated_at)
  VALUES (
    '4cf099a8-6df8-4d70-a3eb-053cb48f9f1f',
    '2026-01-15 16:49:01+00',
    'fireflies',
    '01KF18YYJQDFXTMPXR0034RKPP',
    'Encamp // Website Feedback: Nina Belina and Kyley Crews (Jenny B.)',
